import { createContext, useContext, useState, useEffect } from "react";
import { api } from "@/lib/api";

const AuthContext = createContext();

export function AuthProvider({ children }) {
    // Admin auth
    const [isAdmin, setIsAdmin] = useState(false);
    const [adminKey, setAdminKey] = useState(() => localStorage.getItem("slb_admin_key") || "");

    // User auth
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [user, setUser] = useState(null);
    const [token, setToken] = useState(() => localStorage.getItem("slb_token") || "");
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Check admin status
        if (adminKey) {
            setIsAdmin(true);
        }

        // Check user auth and validate token on mount
        if (token) {
            validateToken();
        } else {
            setLoading(false);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const validateToken = async () => {
        try {
            const { data } = await api.get("/auth/me", {
                headers: { Authorization: `Bearer ${token}` }
            });
            setUser(data.user);
            setIsLoggedIn(true);
        } catch (error) {
            console.log("Token invalid, clearing auth");
            localStorage.removeItem("slb_token");
            setToken("");
            setUser(null);
            setIsLoggedIn(false);
        } finally {
            setLoading(false);
        }
    };

    const loginUser = async (email, password) => {
        try {
            const { data } = await api.post("/auth/login", { email, password });
            localStorage.setItem("slb_token", data.token);
            setToken(data.token);
            setUser(data.user);
            setIsLoggedIn(true);
            return data;
        } catch (error) {
            throw new Error(error.response?.data?.detail || "Login failed");
        }
    };

    const registerUser = async (name, email, password) => {
        try {
            const { data } = await api.post("/auth/register", {
                name,
                email,
                password
            });
            localStorage.setItem("slb_token", data.token);
            setToken(data.token);
            setUser(data.user);
            setIsLoggedIn(true);
            return data;
        } catch (error) {
            throw new Error(error.response?.data?.detail || "Registration failed");
        }
    };

    const logoutUser = () => {
        localStorage.removeItem("slb_token");
        setToken("");
        setUser(null);
        setIsLoggedIn(false);
    };

    // Admin methods
    const loginAdmin = (key) => {
        localStorage.setItem("slb_admin_key", key);
        setAdminKey(key);
        setIsAdmin(true);
    };

    const logoutAdmin = () => {
        localStorage.removeItem("slb_admin_key");
        setAdminKey("");
        setIsAdmin(false);
    };

    const logout = () => {
        logoutUser();
        logoutAdmin();
    };

    return (
        <AuthContext.Provider
            value={{
                // Admin
                isAdmin,
                adminKey,
                loginAdmin,
                logoutAdmin,

                // User
                isLoggedIn,
                user,
                token,
                loading,
                loginUser,
                registerUser,
                logoutUser,

                // General
                logout,
            }}
        >
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error("useAuth must be used within AuthProvider");
    }
    return context;
}
